using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes the input message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo back")] string message) =>
        $"[{DateTime.UtcNow:O}] {message}";

    [McpServerTool, Description("Adds two numbers together.")]
    public static double Add(
        [Description("First number")] double a,
        [Description("Second number")] double b) =>
        a + b;
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(UriTemplate = "config://app", Name = "App Config",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { Logging = true, Metrics = true }
        }, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(UriTemplate = "status://health", Name = "Health Status",
        MimeType = "application/json"),
     Description("Returns the current server health status.")]
    public static string GetHealthStatus() =>
        JsonSerializer.Serialize(new
        {
            Status = "Healthy",
            Uptime = Environment.TickCount64 / 1000,
            Timestamp = DateTime.UtcNow
        }, new JsonSerializerOptions { WriteIndented = true });
}

